```python
def mult_mod(a, b, m):
    c = [
        [a[0][0] * b[0][0] + a[0][1] * b[1][0], a[0][0] * b[0][1] + a[0][1] * b[1][1]],
        [a[1][0] * b[0][0] + a[1][1] * b[1][0], a[1][0] * b[0][1] + a[1][1] * b[1][1]],
    ]
    for i in range(2):
        for j in range(2):
            c[i][j] %= m
    return c

def pow_mod(n, m):
    p = [[1, 1], [1, 0]]
    a = [[1, 0], [0, 1]]
    while n > 0:
        if n % 2 == 1:
            a = mult_mod(a, p, m)
        p = mult_mod(p, p, m)
        n = n // 2
    return a

def fib(n, m):
    a = pow_mod(n, m)
    return a[0][1]

def egcd(a, b):
    if b == 0:
        return 1, 0, a
    x1, y1, g = egcd(b, a % b)
    return y1, x1 - (a // b) * y1, g

def crt(a0, n0, a1, n1):
    x, y, g = egcd(n0, n1)
    if (a0 - a1) % g != 0:
        return 0, -1
    lcm = n0 // g * n1
    x0 = (a0 + (a1 - a0) // g * x % (n1 // g) * n0) % lcm
    return x0, lcm

def find_positions(f, m, max_len):
    positions = []
    a, b = 0, 1
    for i in range(max_len):
        if a == f % m:
            positions.append(i)
        a, b = b, (a + b) % m
    return positions

def main():
    f = int(input())
    MOD = 1013
    pisano_period = 1013 * 8  # The Pisano period for modulo 1013 is 1013*8

    # Find all positions where Fibonacci mod 1013 equals f
    positions = []
    a, b = 0, 1
    for i in range(pisano_period):
        if a == f % MOD:
            positions.append(i)
        a, b = b, (a + b) % MOD

    if not positions:
        print(-1)
    else:
        print(min(positions))

if __name__ == "__main__":
    main()
